function applyCoupon(code, userId) {
  // Check if coupon exists and is not expired or used
  const coupon = couponsData.find(coupon => coupon.code === code && new Date() < coupon.expiryDate);

  if (!coupon) return 'Invalid coupon';
  if (coupon.usedBy !== null) return 'Coupon already used';

  // Mark as used and apply discount
  const index = couponsData.findIndex(coupon => coupon.code === code);
  couponsData[index].usedBy = userId;
  saveCoupons();

  // Apply discount logic
  let discount = coupon.discount;
  // ... add the discount application logic here

  return `Successfully applied ${discount}% off coupon ${code}`;
}

function saveCoupons() {
  const data = JSON.stringify(couponsData);
  fs.writeFileSync('coupons.json', data);
}